def token_case(s):
    tokens = s.split('_')
    exception_list = ['URL', 'ID']

    camel_case_parts = []
    for i, token in enumerate(tokens):
        if token in exception_list:
            camel_case_parts.append(token)
        elif i == 0:
            camel_case_parts.append(token.lower())
        else:
            camel_case_parts.append(token.capitalize())

    return ''.join(camel_case_parts)
